fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    use std::collections::HashMap;

    let c = c as usize;
    let mut graph = HashMap::new();
    for conn in &connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        graph.entry(u).or_insert_with(Vec::new).push(v);
        graph.entry(v).or_insert_with(Vec::new).push(u);
    }

    let mut parent = vec![0; c + 1];
    let mut rank = vec![1; c + 1];

    fn find(parent: &mut Vec<usize>, u: usize) -> usize {
        if parent[u] != u {
            parent[u] = find(parent, parent[u]);
        }
        parent[u]
    }

    fn union(parent: &mut Vec<usize>, rank: &mut Vec<usize>, u: usize, v: usize) {
        let u_root = find(parent, u);
        let v_root = find(parent, v);
        if u_root == v_root {
            return;
        }
        if rank[u_root] < rank[v_root] {
            parent[u_root] = v_root;
        } else {
            parent[v_root] = u_root;
            if rank[u_root] == rank[v_root] {
                rank[u_root] += 1;
            }
        }
    }

    for i in 1..=c {
        parent[i] = i;
    }

    for conn in &connections {
        let u = conn[0] as usize;
        let v = conn[1] as usize;
        union(&mut parent, &mut rank, u, v);
    }

    let mut online = vec![true; c + 1];
    let mut result = Vec::new();

    for query in queries {
        if query[0] == 1 {
            let x = query[1] as usize;
            if online[x] {
                result.push(x as i64);
            } else {
                let root = find(&mut parent, x);
                let mut min_online = -1;
                for i in 1..=c {
                    if online[i] && find(&mut parent, i) == root {
                        min_online = i;
                        break;
                    }
                }
                result.push(min_online as i64);
            }
        } else {
            let x = query[1] as usize;
            online[x] = false;
        }
    }

    result
}
